Literal.Value:
'{
  "$schema": "https://vega.github.io/schema/vega-lite/v5.json",

  "width": "container",
  "height": "container",

  "data": { "name": "dataset" },

  "transform": [
    {
      "filter": "datum[''Report Scope''] == ''Filtered''"
    },
    {
      "aggregate": [
        {
          "op": "count",
          "as": "filteredCount"
        }
      ]
    },
    {
      "filter": "datum.filteredCount > 0"
    },
    {
      "calculate": "''Provider Value''",
      "as": "key1"
    },
    {
      "calculate": "''#0C436A''",
      "as": "color1"
    },
    {
      "calculate": "8",
      "as": "x1"
    },
    {
      "calculate": "''Benchmark''",
      "as": "key2"
    },
    {
      "calculate": "''#3DB3E3''",
      "as": "color2"
    },
    {
      "calculate": "88",
      "as": "x2"
    },
    {
      "fold": ["key1", "key2"],
      "as": ["keyField", "keyValue"]
    },
    {
      "calculate": "datum.keyField == ''key1'' ? datum.key1 : datum.key2",
      "as": "key"
    },
    {
      "calculate": "datum.keyField == ''key1'' ? datum.color1 : datum.color2",
      "as": "color"
    },
    {
      "calculate": "datum.keyField == ''key1'' ? datum.x1 : datum.x2",
      "as": "x"
    },
    {
      "calculate": "14",
      "as": "y"
    }
  ],

  "layer": [
    {
      "mark": { "type": "rect", "width": 10, "height": 10, "cornerRadius": 2 },
      "encoding": {
        "x": { "field": "x", "type": "quantitative", "axis": null },
        "y": { "field": "y", "type": "quantitative", "axis": null },
        "color": { "field": "color", "type": "nominal", "scale": null }
      }
    },

    {
      "mark": {
        "type": "text",
        "align": "left",
        "baseline": "middle",
        "dx": 14,
        "fontSize": 9
      },
      "encoding": {
        "x": { "field": "x", "type": "quantitative", "axis": null },
        "y": { "field": "y", "type": "quantitative", "axis": null },
        "text": { "field": "key", "type": "nominal" },
        "color": { "field": "color", "type": "nominal", "scale": null }
      }
    }
  ],

  "config": {
    "view": { "stroke": null },
    "axis": { "grid": false, "domain": false, "ticks": false, "labels": false }
  }
}'
